<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Kanban Board</title>
  <style>
    :root {
      --bg-color: #f4f5f7;
      --board-bg: #ffffff;
      --column-bg: #ebecf0;
      --card-bg: #ffffff;
      --text-color: #172b4d;
      --text-muted: #5e6c84;
      --primary-color: #0052cc;
      --primary-hover: #0065ff;
      --danger-color: #eb5a46;
      --danger-hover: #cf513d;
      --border-radius: 8px;
      --shadow: 0 1px 3px rgba(0,0,0,0.12), 0 1px 2px rgba(0,0,0,0.24);
      --font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    }

    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      font-family: var(--font-family);
      background-color: var(--bg-color);
      color: var(--text-color);
      padding: 20px;
      height: 100vh;
      display: flex;
      flex-direction: column;
    }

    header {
      margin-bottom: 20px;
      flex-shrink: 0;
    }

    h1 {
      font-size: 1.75rem;
      font-weight: 700;
      margin-bottom: 15px;
      color: var(--text-color);
    }

    .controls {
      display: flex;
      gap: 10px;
      max-width: 500px;
    }

    #new-card {
      flex-grow: 1;
      padding: 10px 14px;
      border: 2px solid #dfe1e6;
      border-radius: var(--border-radius);
      font-size: 0.95rem;
      outline: none;
      transition: border-color 0.2s ease;
    }

    #new-card:focus {
      border-color: var(--primary-color);
    }

    #add-card {
      background-color: var(--primary-color);
      color: white;
      border: none;
      padding: 10px 20px;
      border-radius: var(--border-radius);
      font-weight: 600;
      cursor: pointer;
      font-size: 0.95rem;
      transition: background-color 0.2s ease;
    }

    #add-card:hover {
      background-color: var(--primary-hover);
    }

    .board {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 20px;
      flex-grow: 1;
      min-height: 0; /* Allows columns to scroll independently if needed */
    }

    .column {
      background-color: var(--column-bg);
      border-radius: var(--border-radius);
      display: flex;
      flex-direction: column;
      padding: 15px;
      max-height: 100%;
    }

    .column-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 15px;
      font-weight: 700;
      font-size: 1.1rem;
      color: var(--text-color);
      user-select: none;
    }

    .count {
      background-color: rgba(9, 30, 66, 0.08);
      color: var(--text-muted);
      padding: 2px 8px;
      border-radius: 12px;
      font-size: 0.85rem;
      font-weight: 600;
    }

    .card-container {
      flex-grow: 1;
      overflow-y: auto;
      display: flex;
      flex-direction: column;
      gap: 10px;
      min-height: 150px; /* Ensures drop zone is accessible when empty */
      padding-bottom: 20px;
    }

    .card {
      background-color: var(--card-bg);
      border-radius: 6px;
      padding: 12px;
      box-shadow: var(--shadow);
      cursor: grab;
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
      gap: 10px;
      user-select: none;
      transition: transform 0.1s ease, box-shadow 0.1s ease;
    }

    .card:active {
      cursor: grabbing;
    }

    .card.dragging {
      opacity: 0.5;
      transform: scale(0.98);
    }

    .card-text {
      font-size: 0.95rem;
      line-height: 1.4;
      word-break: break-word;
      color: var(--text-color);
    }

    .card-del {
      background: none;
      border: none;
      color: var(--text-muted);
      cursor: pointer;
      font-size: 1.1rem;
      line-height: 1;
      padding: 2px 6px;
      border-radius: 4px;
      transition: background-color 0.2s, color 0.2s;
    }

    .card-del:hover {
      background-color: rgba(235, 90, 70, 0.1);
      color: var(--danger-color);
    }

    /* Drag over visual cue */
    .column.drag-over {
      background-color: #dfe1e6;
      outline: 2px dashed var(--primary-color);
      outline-offset: -2px;
    }

    @media (max-width: 768px) {
      .board {
        grid-template-columns: 1fr;
        overflow-y: auto;
      }
      body {
        height: auto;
      }
      .column {
        max-height: 400px;
      }
    }
  </style>
</head>
<body>

  <header>
    <h1>Kanban Board</h1>
    <div class="controls">
      <input type="text" id="new-card" placeholder="Enter card title..." autocomplete="off">
      <button id="add-card">Add Card</button>
    </div>
  </header>

  <main class="board">
    <!-- To Do Column -->
    <section class="column" id="col-todo">
      <div class="column-header">
        <span>To Do</span>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </section>

    <!-- Doing Column -->
    <section class="column" id="col-doing">
      <div class="column-header">
        <span>Doing</span>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </section>

    <!-- Done Column -->
    <section class="column" id="col-done">
      <div class="column-header">
        <span>Done</span>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </section>
  </main>

  <script>
    // State management
    let boardState = {
      'col-todo': [],
      'col-doing': [],
      'col-done': []
    };

    // DOM Elements
    const newCardInput = document.getElementById('new-card');
    const addCardBtn = document.getElementById('add-card');
    const columns = {
      'col-todo': document.getElementById('col-todo'),
      'col-doing': document.getElementById('col-doing'),
      'col-done': document.getElementById('col-done')
    };

    // Load state from localStorage on startup
    function loadState() {
      const saved = localStorage.getItem('kanban_board_state');
      if (saved) {
        try {
          boardState = JSON.parse(saved);
        } catch (e) {
          console.error("Failed to parse saved state, resetting.", e);
        }
      }
      renderBoard();
    }

    // Save state to localStorage
    function saveState() {
      localStorage.setItem('kanban_board_state', JSON.stringify(boardState));
    }

    // Generate unique ID for cards
    function generateId() {
      return '_' + Math.random().toString(36).substr(2, 9);
    }

    // Render the entire board based on state
    function renderBoard() {
      Object.keys(columns).forEach(colId => {
        const columnEl = columns[colId];
        const container = columnEl.querySelector('.card-container');
        const countEl = columnEl.querySelector('.count');

        // Clear existing cards
        container.innerHTML = '';

        // Render cards
        const cards = boardState[colId] || [];
        cards.forEach(card => {
          const cardEl = createCardElement(card.id, card.text);
          container.appendChild(cardEl);
        });

        // Update count badge
        countEl.textContent = cards.length;
      });
    }

    // Create a single card DOM element
    function createCardElement(id, text) {
      const card = document.createElement('div');
      card.className = 'card';
      card.draggable = true;
      card.dataset.id = id;

      const textSpan = document.createElement('span');
      textSpan.className = 'card-text';
      textSpan.textContent = text;

      const delBtn = document.createElement('button');
      delBtn.className = 'card-del';
      delBtn.innerHTML = '&times;';
      delBtn.title = 'Delete card';

      // Delete event handler
      delBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        deleteCard(id);
      });

      card.appendChild(textSpan);
      card.appendChild(delBtn);

      // Drag and Drop Event Listeners on Card
      card.addEventListener('dragstart', (e) => {
        card.classList.add('dragging');
        e.dataTransfer.setData('text/plain', id);
        e.dataTransfer.effectAllowed = 'move';
      });

      card.addEventListener('dragend', () => {
        card.classList.remove('dragging');
        // Remove drag-over styling from all columns just in case
        Object.values(columns).forEach(col => col.classList.remove('drag-over'));
      });

      return card;
    }

    // Add a new card to the To Do column
    function addNewCard() {
      const text = newCardInput.value.trim();
      if (!text) return;

      const newCard = {
        id: generateId(),
        text: text
      };

      boardState['col-todo'].push(newCard);
      saveState();
      renderBoard();

      newCardInput.value = '';
      newCardInput.focus();
    }

    // Delete a card by ID from whichever column it is in
    function deleteCard(id) {
      Object.keys(boardState).forEach(colId => {
        boardState[colId] = boardState[colId].filter(card => card.id !== id);
      });
      saveState();
      renderBoard();
    }

    // Move a card from its current column to a target column
    function moveCard(cardId, targetColId) {
      let cardToMove = null;

      // Find and remove card from its current column
      Object.keys(boardState).forEach(colId => {
        const index = boardState[colId].findIndex(card => card.id === cardId);
        if (index !== -1) {
          cardToMove = boardState[colId].splice(index, 1)[0];
        }
      });

      // Push to target column if found
      if (cardToMove) {
        boardState[targetColId].push(cardToMove);
        saveState();
      }
      renderBoard();
    }

    // Setup Event Listeners
    addCardBtn.addEventListener('click', addNewCard);
    newCardInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') {
        addNewCard();
      }
    });

    // Setup Drag and Drop handlers on Columns
    Object.keys(columns).forEach(colId => {
      const columnEl = columns[colId];

      columnEl.addEventListener('dragover', (e) => {
        e.preventDefault(); // Necessary to allow dropping
        e.dataTransfer.dropEffect = 'move';
        columnEl.classList.add('drag-over');
      });

      columnEl.addEventListener('dragleave', () => {
        columnEl.classList.remove('drag-over');
      });

      columnEl.addEventListener('drop', (e) => {
        e.preventDefault();
        columnEl.classList.remove('drag-over');
        const cardId = e.dataTransfer.getData('text/plain');
        if (cardId) {
          moveCard(cardId, colId);
        }
      });
    });

    // Initialize Board
    loadState();
  </script>
</body>
</html>
